// Map lang codes to display labels
const langLabels = {
    en: 'English', hi: 'Hindi', ml: 'Malayalam',
    fr: 'French', es: 'Spanish', zh: 'Chinese',
    de: 'German', ja: 'Japanese', ru: 'Russian', ar: 'Arabic'
};

function setLang(lang, label) {
    changeLanguage(lang);
    const labelEl = document.getElementById('currentLangLabel');
    if (labelEl) labelEl.innerText = label || langLabels[lang] || lang;
}

function changeLanguage(lang) {
    const elements = document.querySelectorAll('[data-i18n]');
    elements.forEach(el => {
        const key = el.getAttribute('data-i18n');
        const text = (resources[lang] && resources[lang][key]) || (resources['en'] && resources['en'][key]) || key;

        if (el.tagName === 'INPUT' && el.getAttribute('placeholder')) {
            el.placeholder = text;
        } else if (el.tagName === 'TEXTAREA' && el.getAttribute('placeholder')) {
            el.placeholder = text;
        } else {
            if (el.children.length > 0) {
               for (let node of el.childNodes) {
                   if (node.nodeType === Node.TEXT_NODE && node.textContent.trim().length > 0) {
                       node.textContent = node.textContent.startsWith(' ') ? ' ' + text : text;
                   }
               }
               const textSpan = el.querySelector('span:not([class*="mr-"]):not([data-i18n])');
               if (textSpan) textSpan.innerText = text;
            } else {
                el.innerText = text;
            }
        }
    });
    localStorage.setItem('netra_lang', lang);
}

window.addEventListener('load', () => {
    const lang = localStorage.getItem('netra_lang') || 'en';
    // Restore saved label on the button
    const labelEl = document.getElementById('currentLangLabel');
    if (labelEl && lang !== 'en') labelEl.innerText = langLabels[lang] || lang;
    changeLanguage(lang);
});
